import React, { useEffect, useState } from "react";
import { auth, provider } from "../components/firebase_setup";
import { signInWithPopup } from "firebase/auth";
import Home from "./Home";
import { useNavigate } from "react-router-dom";

//If I close the popup it crashes, so gotta do something abt that


function SignIn(){
    
    const[Value,setValue] = useState("");
    const navigate = useNavigate();

    const handlesignIn =()=>{
        signInWithPopup(auth, provider).then(async (data)=>{
            u_email = data.user.email;
            
            setValue(u_email);
            localStorage.setItem("email", u_email);


        })
    }

    useEffect(()=>{
        setValue(localStorage.getItem('email'))
    },[])

    return(
        <div>
            <h1>Welcome to Catsa. To continue Please use your Google account to log in.</h1>
            {Value ? <Home/> :
            <button onClick={handlesignIn}>Sign In With Google</button>
            }
        </div>
    );
}

export default SignIn;
